  ('elementary-0a2fc18c-moex-00963', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設某一業者的石化產品製造過程中會產生極大的空氣污染，政府為解決此一污染造成的外部性問題， 下列何者不是可行的措施？', '["設定財產權", "藉由市場機制解決", "對業者減產補貼", "對業者課稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00964', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '下列關於所得稅制設計的敘述，何者錯誤？', '["受益原則指的是稅制設計中，依人們從社會以及從政府獲取的服務之多寡，設計其應負擔的稅款的原則", "若越高所得者需繳交越高稅率，代表該租稅制度之設計符合能力原則", "臺灣目前實施的累進所得稅率制是一種符合能力原則的設計", "若所得稅制中的特別條款讓某些特殊情況家庭減少需繳的所得稅，代表該設計未能保有稅制設計的受 益原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00965', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '下列何者為景氣領先指標？', '["失業率", "製造業存貨率", "工業生產指數", "外銷訂單指數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00966', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設甲國的生產函數是Y=N0.5K0.5，其中Y是總產出、N是勞動力、K是總資本；並且資本折舊率、勞動 人口成長率、儲蓄率分別是3.5%、1.5%、30%。根據梭羅（Solow）成長模型，甲國在黃金律（goldenrule） 之下，其每人資本存量是多少？', '["5", "25", "50", "100"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00967', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設其他條件不變且政府政策沒有時間落後問題。當總合需求增加時，下列何種政策組合可以降低經濟 波動的幅度？', '["政府增加購買支出且中央銀行調高應提準備率", "政府增加購買支出且中央銀行調降應提準備率", "政府減少購買支出且中央銀行調高應提準備率", "政府減少購買支出且中央銀行調降應提準備率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00968', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '某餐廳老闆發現漲價可以提高餐廳營收，由此可判斷該餐廳需求的價格彈性絕對值：', '["趨近無窮大", "大於1", "等於1", "小於1"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00969', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '因應疫情造成經濟衰退，中央銀行採取降息措施，而市場也預期中央銀行會持續降低利率，下述何者是 導致本國通貨貶值最正確的敘述？', '["因預期本國通貨貶值，本國通貨的需求減少", "本國通貨的供給增加", "本國通貨的供給增加但需求減少", "本國通貨需求減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00970', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '許多實證文獻指出，購買力平價（purchasingpowerparity）在短期不成立。下列何項是造成購買力平價不 成立的最直接原因？', '["有些商品和服務並不容易在國際間進行交易", "出口值不等於進口值", "外匯存底快速累積", "資本自由移動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00971', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '在倫敦，一美元可換0.8英磅；在東京，一英磅可換130日圓；在紐約，一美元可換100日圓，則國際外 匯市場三地套匯行為會出現：', '["東京對日圓有超額供給，而紐約對美元有超額需求", "紐約對日圓有超額需求，而倫敦對美元有超額供給", "在倫敦與在紐約，美元皆有超額供給", "東京對日圓有超額需求，而倫敦對美元有超額供給"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00972', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '考慮以下三個方案：①政府支出增加3,000萬  ②政府減稅3,000萬  ③政府支出增加4,000萬且課稅增 加1,000萬。依據政府支出與課稅為外生給定的簡單凱因斯模型，三個方案提升產出的效果，由高到低的 排列順序為何？', '["", ">", ">", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
